"use client";

import React, { useState } from "react";
import {
  LayoutDashboard,
  Package,
  Search,
  ClipboardCheck,
  Users,
  Bell,
  CheckCircle,
  XCircle,
  Clock,
  TrendingUp,
  AlertTriangle,
  Eye,
  MoreVertical,
  Menu,
  X as CloseIcon
} from "lucide-react";

// Mock Data
const statsData = {
  totalLost: 42,
  totalFound: 58,
  totalClaims: 23,
  itemsReturned: 35,
  pendingVerification: 8,
  activeClaims: 12
};

const recentClaims = [
  {
    id: 1,
    itemName: "Black Backpack",
    claimer: "John Doe",
    claimerEmail: "john@example.com",
    status: "pending",
    date: "2024-12-05",
    location: "Library"
  },
  {
    id: 2,
    itemName: "iPhone 13",
    claimer: "Jane Smith",
    claimerEmail: "jane@example.com",
    status: "approved",
    date: "2024-12-04",
    location: "Cafeteria"
  },
  {
    id: 3,
    itemName: "Student ID Card",
    claimer: "Mike Johnson",
    claimerEmail: "mike@example.com",
    status: "pending",
    date: "2024-12-04",
    location: "Gym"
  },
  {
    id: 4,
    itemName: "Headphones",
    claimer: "Sarah Williams",
    claimerEmail: "sarah@example.com",
    status: "rejected",
    date: "2024-12-03",
    location: "Study Hall"
  },
  {
    id: 5,
    itemName: "Water Bottle",
    claimer: "Tom Brown",
    claimerEmail: "tom@example.com",
    status: "pending",
    date: "2024-12-03",
    location: "Classroom 301"
  }
];

const recentActivities = [
  { id: 1, action: "New claim submitted", item: "Black Backpack", time: "5 mins ago", type: "claim" },
  { id: 2, action: "Item verified", item: "iPhone 13", time: "1 hour ago", type: "verify" },
  { id: 3, action: "Claim approved", item: "Student ID", time: "2 hours ago", type: "approve" },
  { id: 4, action: "New found item", item: "Headphones", time: "3 hours ago", type: "found" },
  { id: 5, action: "Item returned", item: "Car Keys", time: "5 hours ago", type: "returned" }
];

const AdminDashboard = () => {
  // Keeping sidebarOpen/setActiveMenu for potential use (e.g., triggering layout sidebar)
  // but removing the actual sidebar UI and local state for activeMenu
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [claims, setClaims] = useState(recentClaims);

  // Handlers
  const handleApproveClaim = (claimId) => {
    setClaims(claims.map(c => c.id === claimId ? { ...c, status: 'approved' } : c));
  };

  const handleRejectClaim = (claimId) => {
    setClaims(claims.map(c => c.id === claimId ? { ...c, status: 'rejected' } : c));
  };

  const getStatusBadge = (status) => {
    const styles = {
      pending: "bg-yellow-100 text-yellow-800 border-yellow-200",
      approved: "bg-green-100 text-green-800 border-green-200",
      rejected: "bg-red-100 text-red-800 border-red-200"
    };
    // Correcting template literal usage for Tailwind classes
    return `px-2 py-1 rounded text-xs font-medium border ${styles[status] || styles.pending}`;
  };

  // Main Content Container: Removed 'lg:ml-64'
  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden">
      
      {/* Main Content (Now without the margin/offset for the layout-provided sidebar) */}
      <div className="flex-1 flex flex-col overflow-hidden">
        
        {/* Top Navigation */}
        <header className="bg-white border-b border-gray-200 px-6 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-4">
              {/* This button should now trigger the sidebar from the Layout context */}
              <button onClick={() => setSidebarOpen(true)} className="lg:hidden">
                <Menu size={24} className="text-gray-600" />
              </button>
              <h2 className="text-2xl font-semibold text-gray-900">Dashboard</h2>
            </div>

            <div className="flex items-center space-x-4">
              <button className="relative p-2 text-gray-600 hover:bg-gray-100 rounded-lg">
                <Bell size={20} />
                <span className="absolute top-1 right-1 w-2 h-2 bg-red-500 rounded-full"></span>
              </button>
            </div>
          </div>
        </header>

        {/* Dashboard Content */}
        <main className="flex-1 overflow-y-auto p-6">
          
          {/* Stats Grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 mb-6">
            <div className="bg-white rounded-lg border border-gray-200 p-5">
              <div className="flex items-center justify-between mb-3">
                <div>
                  <p className="text-sm text-gray-600 font-medium">Total Lost Items</p>
                  <p className="text-3xl font-bold text-gray-900 mt-1">{statsData.totalLost}</p>
                </div>
                <div className="bg-indigo-100 p-3 rounded-lg">
                  <Package className="w-6 h-6 text-indigo-800" />
                </div>
              </div>
              <div className="flex items-center text-sm">
                <TrendingUp className="w-4 h-4 text-green-500 mr-1" />
                <span className="text-green-600 font-medium">+12%</span>
                <span className="text-gray-500 ml-1">from last month</span>
              </div>
            </div>

            <div className="bg-white rounded-lg border border-gray-200 p-5">
              <div className="flex items-center justify-between mb-3">
                <div>
                  <p className="text-sm text-gray-600 font-medium">Total Found Items</p>
                  <p className="text-3xl font-bold text-gray-900 mt-1">{statsData.totalFound}</p>
                </div>
                <div className="bg-green-100 p-3 rounded-lg">
                  <Search className="w-6 h-6 text-green-700" />
                </div>
              </div>
              <div className="flex items-center text-sm">
                <TrendingUp className="w-4 h-4 text-green-500 mr-1" />
                <span className="text-green-600 font-medium">+8%</span>
                <span className="text-gray-500 ml-1">from last month</span>
              </div>
            </div>

            <div className="bg-white rounded-lg border border-gray-200 p-5">
              <div className="flex items-center justify-between mb-3">
                <div>
                  <p className="text-sm text-gray-600 font-medium">Items Returned</p>
                  <p className="text-3xl font-bold text-gray-900 mt-1">{statsData.itemsReturned}</p>
                </div>
                <div className="bg-blue-100 p-3 rounded-lg">
                  <CheckCircle className="w-6 h-6 text-blue-700" />
                </div>
              </div>
              <div className="flex items-center text-sm">
                <TrendingUp className="w-4 h-4 text-green-500 mr-1" />
                <span className="text-green-600 font-medium">+15%</span>
                <span className="text-gray-500 ml-1">from last month</span>
              </div>
            </div>

            <div className="bg-white rounded-lg border border-gray-200 p-5">
              <div className="flex items-center justify-between mb-3">
                <div>
                  <p className="text-sm text-gray-600 font-medium">Total Claims</p>
                  <p className="text-3xl font-bold text-gray-900 mt-1">{statsData.totalClaims}</p>
                </div>
                <div className="bg-purple-100 p-3 rounded-lg">
                  <ClipboardCheck className="w-6 h-6 text-purple-700" />
                </div>
              </div>
              <div className="flex items-center text-sm">
                <Clock className="w-4 h-4 text-gray-500 mr-1" />
                <span className="text-gray-600">{statsData.activeClaims} active</span>
              </div>
            </div>

            <div className="bg-white rounded-lg border border-gray-200 p-5">
              <div className="flex items-center justify-between mb-3">
                <div>
                  <p className="text-sm text-gray-600 font-medium">Pending Verification</p>
                  <p className="text-3xl font-bold text-gray-900 mt-1">{statsData.pendingVerification}</p>
                </div>
                <div className="bg-yellow-100 p-3 rounded-lg">
                  <AlertTriangle className="w-6 h-6 text-yellow-700" />
                </div>
              </div>
              <div className="flex items-center text-sm">
                <Clock className="w-4 h-4 text-yellow-600 mr-1" />
                <span className="text-yellow-700 font-medium">Needs attention</span>
              </div>
            </div>

            <div className="bg-white rounded-lg border border-gray-200 p-5">
              <div className="flex items-center justify-between mb-3">
                <div>
                  <p className="text-sm text-gray-600 font-medium">Success Rate</p>
                  <p className="text-3xl font-bold text-gray-900 mt-1">85%</p>
                </div>
                <div className="bg-green-100 p-3 rounded-lg">
                  <TrendingUp className="w-6 h-6 text-green-700" />
                </div>
              </div>
              <div className="flex items-center text-sm">
                <span className="text-gray-600">Items successfully returned</span>
              </div>
            </div>
          </div>

          {/* Two Column Layout */}
          <div className="grid lg:grid-cols-3 gap-6">
            
            {/* Recent Claims Table */}
            <div className="lg:col-span-2 bg-white rounded-lg border border-gray-200">
              <div className="px-5 py-4 border-b border-gray-200">
                <h3 className="text-lg font-semibold text-gray-900">Recent Claims</h3>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead className="bg-gray-50 border-b border-gray-200">
                    <tr>
                      <th className="px-5 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Item</th>
                      <th className="px-5 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Claimer</th>
                      <th className="px-5 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Location</th>
                      <th className="px-5 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Status</th>
                      <th className="px-5 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Actions</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-200">
                    {claims.map((claim) => (
                      <tr key={claim.id} className="hover:bg-gray-50">
                        <td className="px-5 py-4">
                          <div>
                            <p className="text-sm font-medium text-gray-900">{claim.itemName}</p>
                            <p className="text-xs text-gray-500">{claim.date}</p>
                          </div>
                        </td>
                        <td className="px-5 py-4">
                          <div>
                            <p className="text-sm text-gray-900">{claim.claimer}</p>
                            <p className="text-xs text-gray-500">{claim.claimerEmail}</p>
                          </div>
                        </td>
                        <td className="px-5 py-4">
                          <p className="text-sm text-gray-700">{claim.location}</p>
                        </td>
                        <td className="px-5 py-4">
                          <span className={getStatusBadge(claim.status)}>
                            {claim.status}
                          </span>
                        </td>
                        <td className="px-5 py-4">
                          {claim.status === 'pending' ? (
                            <div className="flex items-center space-x-2">
                              <button
                                onClick={() => handleApproveClaim(claim.id)}
                                className="p-1.5 text-green-600 hover:bg-green-50 rounded"
                                title="Approve"
                              >
                                <CheckCircle size={18} />
                              </button>
                              <button
                                onClick={() => handleRejectClaim(claim.id)}
                                className="p-1.5 text-red-600 hover:bg-red-50 rounded"
                                title="Reject"
                              >
                                <XCircle size={18} />
                              </button>
                              <button className="p-1.5 text-indigo-600 hover:bg-indigo-50 rounded" title="View">
                                <Eye size={18} />
                              </button>
                            </div>
                          ) : (
                            <button className="p-1.5 text-gray-600 hover:bg-gray-50 rounded">
                              <Eye size={18} />
                            </button>
                          )}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>

            {/* Recent Activity */}
            <div className="bg-white rounded-lg border border-gray-200">
              <div className="px-5 py-4 border-b border-gray-200">
                <h3 className="text-lg font-semibold text-gray-900">Recent Activity</h3>
              </div>
              <div className="p-5">
                <div className="space-y-4">
                  {recentActivities.map((activity) => (
                    <div key={activity.id} className="flex items-start space-x-3">
                      <div className={`p-2 rounded-lg ${
                        activity.type === 'claim' ? 'bg-blue-100' :
                        activity.type === 'verify' ? 'bg-green-100' :
                        activity.type === 'approve' ? 'bg-purple-100' :
                        activity.type === 'found' ? 'bg-yellow-100' :
                        'bg-gray-100'
                      }`}>
                        {activity.type === 'claim' && <ClipboardCheck className="w-4 h-4 text-blue-700" />}
                        {activity.type === 'verify' && <CheckCircle className="w-4 h-4 text-green-700" />}
                        {activity.type === 'approve' && <CheckCircle className="w-4 h-4 text-purple-700" />}
                        {activity.type === 'found' && <Search className="w-4 h-4 text-yellow-700" />}
                        {activity.type === 'returned' && <Package className="w-4 h-4 text-gray-700" />}
                      </div>
                      <div className="flex-1">
                        <p className="text-sm font-medium text-gray-900">{activity.action}</p>
                        <p className="text-xs text-gray-600">{activity.item}</p>
                        <p className="text-xs text-gray-500 mt-1">{activity.time}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
};

export default AdminDashboard;